package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.AdmissionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admissions/discharge")public class AdmissionDischargeServlet extends HttpServlet{private final AdmissionService service;public AdmissionDischargeServlet(){this(new AdmissionServiceImpl());}public AdmissionDischargeServlet(AdmissionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));Admission a=id==null?null:service.getAdmission(id,AdmissionRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}q.setAttribute("admission",a);q.getRequestDispatcher("/WEB-INF/views/admissions/discharge.jsp").forward(q,r);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{DischargeForm f=new DischargeForm();f.setAdmissionId(AdmissionRequest.id(q.getParameter("admissionId")));f.setDischargeSummary(q.getParameter("dischargeSummary"));f.setCreateOrUpdateBill("on".equals(q.getParameter("createOrUpdateBill")));f.setAdditionalRoomChargeDescription(q.getParameter("additionalRoomChargeDescription"));ServiceResult<Void>x=service.dischargePatient(f,AdmissionRequest.audit(q),AdmissionRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admissions/view?id="+f.getAdmissionId());return;}q.setAttribute("errorMessage",x.getMessage());doGet(q,r);}}
